diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..f47d65393e36 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -6464,6 +6464,141 @@ Instruction *InstCombinerImpl::foldICmpUsingBoolRange(ICmpInst &I) {
     }
   }

+  // Handle icmp (add (zext i1 X), (zext i1 Y)), C
+  // For zext + zext, the sum range is [0, 1, 2]
+  const APInt *C2;
+  if (match(I.getOperand(0), m_c_Add(m_ZExt(m_Value(X)), m_ZExt(m_Value(Y)))) &&
+      match(I.getOperand(1), m_APInt(C2)) &&
+      X->getType()->isIntOrIntVectorTy(1) &&
+      Y->getType()->isIntOrIntVectorTy(1)) {
+    unsigned BitWidth2 = C2->getBitWidth();
+    Pred = I.getPredicate();
+    APInt Zero2 = APInt::getZero(BitWidth2);
+    APInt Two2(BitWidth2, 2);
+    APInt One2(BitWidth2, 1);
+
+    // Handle out-of-range constants first
+    // For zext, range is [0, 1, 2]
+    if (C2->slt(Zero2)) {
+      // sum < 0 is impossible
+      if (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_ULT ||
+          Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SLE)
+        return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+      if (Pred == ICmpInst::ICMP_NE || Pred == ICmpInst::ICMP_UGT ||
+          Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SGE)
+        return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+    } else if (C2->ugt(Two2)) {
+      // sum > 2 is impossible
+      if (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_UGT ||
+          Pred == ICmpInst::ICMP_UGE || Pred == ICmpInst::ICMP_SGT ||
+          Pred == ICmpInst::ICMP_SGE)
+        return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+      if (Pred == ICmpInst::ICMP_NE || Pred == ICmpInst::ICMP_ULT ||
+          Pred == ICmpInst::ICMP_ULE || Pred == ICmpInst::ICMP_SLT ||
+          Pred == ICmpInst::ICMP_SLE)
+        return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+    }
+
+    if (I.getOperand(0)->hasOneUse()) {
+      // icmp eq (add (zext X), (zext Y)), 1 --> xor X, Y
+      // sum == 1 means exactly one operand is 1
+      if (Pred == ICmpInst::ICMP_EQ && *C2 == One2)
+        return BinaryOperator::CreateXor(X, Y);
+
+      // icmp ne (add (zext X), (zext Y)), 1 --> xnor X, Y = not xor
+      // sum != 1 means both are 0 or both are 1
+      if (Pred == ICmpInst::ICMP_NE && *C2 == One2)
+        return BinaryOperator::CreateNot(Builder.CreateXor(X, Y));
+
+      // icmp eq (add (zext X), (zext Y)), 0 --> and (not X), (not Y)
+      // sum == 0 means both are 0
+      if (Pred == ICmpInst::ICMP_EQ && *C2 == Zero2)
+        return BinaryOperator::CreateAnd(Builder.CreateNot(X),
+                                         Builder.CreateNot(Y));
+
+      // icmp ne (add (zext X), (zext Y)), 0 --> or X, Y
+      // sum != 0 means at least one is 1
+      if (Pred == ICmpInst::ICMP_NE && *C2 == Zero2)
+        return BinaryOperator::CreateOr(X, Y);
+
+      // icmp eq (add (zext X), (zext Y)), 2 --> and X, Y
+      // sum == 2 means both are 1
+      if (Pred == ICmpInst::ICMP_EQ && *C2 == Two2)
+        return BinaryOperator::CreateAnd(X, Y);
+
+      // icmp ne (add (zext X), (zext Y)), 2 --> or (not X), (not Y)
+      // sum != 2 means at least one is 0
+      if (Pred == ICmpInst::ICMP_NE && *C2 == Two2)
+        return BinaryOperator::CreateOr(Builder.CreateNot(X),
+                                        Builder.CreateNot(Y));
+    }
+  }
+
+
+
+  // Handle icmp (add (sext i1 X), (sext i1 Y)), C
+  // For sext + sext, the sum range is [-2, -1, 0]
+  const APInt *C3;
+  if (match(I.getOperand(0), m_c_Add(m_SExt(m_Value(X)), m_SExt(m_Value(Y)))) &&
+      match(I.getOperand(1), m_APInt(C3)) &&
+      X->getType()->isIntOrIntVectorTy(1) &&
+      Y->getType()->isIntOrIntVectorTy(1)) {
+    unsigned BitWidth3 = C3->getBitWidth();
+    Pred = I.getPredicate();
+    APInt Zero3 = APInt::getZero(BitWidth3);
+    APInt MinusOne3 = APInt::getAllOnes(BitWidth3);  // -1
+    APInt MinusTwo3(BitWidth3, 0);
+    MinusTwo3 -= 2;  // -2
+
+    // Handle out-of-range constants first
+    // For sext, range is [-2, -1, 0]
+    if (C3->sgt(Zero3)) {
+      // sum > 0 is impossible
+      if (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_UGT ||
+          Pred == ICmpInst::ICMP_UGE || Pred == ICmpInst::ICMP_SGT ||
+          Pred == ICmpInst::ICMP_SGE)
+        return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+      if (Pred == ICmpInst::ICMP_NE || Pred == ICmpInst::ICMP_ULT ||
+          Pred == ICmpInst::ICMP_ULE || Pred == ICmpInst::ICMP_SLT ||
+          Pred == ICmpInst::ICMP_SLE)
+        return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+    }
+
+    if (I.getOperand(0)->hasOneUse()) {
+      // icmp eq (add (sext X), (sext Y)), -2 --> and X, Y
+      // sum == -2 means both operands are -1 (both args true)
+      if (Pred == ICmpInst::ICMP_EQ && *C3 == MinusTwo3)
+        return BinaryOperator::CreateAnd(X, Y);
+
+      // icmp ne (add (sext X), (sext Y)), -2 --> or (not X), (not Y)
+      // sum != -2 means at least one is not -1
+      if (Pred == ICmpInst::ICMP_NE && *C3 == MinusTwo3)
+        return BinaryOperator::CreateOr(Builder.CreateNot(X),
+                                        Builder.CreateNot(Y));
+
+      // icmp eq (add (sext X), (sext Y)), -1 --> xor X, Y
+      // sum == -1 means exactly one operand is -1
+      if (Pred == ICmpInst::ICMP_EQ && *C3 == MinusOne3)
+        return BinaryOperator::CreateXor(X, Y);
+
+      // icmp ne (add (sext X), (sext Y)), -1 --> xnor = not xor
+      // sum != -1 means both are -1 or both are 0
+      if (Pred == ICmpInst::ICMP_NE && *C3 == MinusOne3)
+        return BinaryOperator::CreateNot(Builder.CreateXor(X, Y));
+
+      // icmp eq (add (sext X), (sext Y)), 0 --> and (not X), (not Y)
+      // sum == 0 means both are 0 (both args false)
+      if (Pred == ICmpInst::ICMP_EQ && *C3 == Zero3)
+        return BinaryOperator::CreateAnd(Builder.CreateNot(X),
+                                         Builder.CreateNot(Y));
+
+      // icmp ne (add (sext X), (sext Y)), 0 --> or X, Y
+      // sum != 0 means at least one is -1
+      if (Pred == ICmpInst::ICMP_NE && *C3 == Zero3)
+        return BinaryOperator::CreateOr(X, Y);
+    }
+  }
+
   return nullptr;
 }

